vector<int> Solution::validSequence(string word1, string word2) {
    int n = word1.size(), m = word2.size();
    vector<int> res;
    for (int i = 0; i < n; i++) {
        int diff = 0;
        for (int j = 0; j < m; j++) {
            if (word1[i + j] != word2[j]) diff++;
            if (diff > 1) break;
            if (j == m - 1) {
                res.push_back(i + j);
                diff = 1;
            }
        }
        if (diff > 1) break;
    }
    sort(res.begin(), res.end());
    return res;
}
